<template><div class="prescription-page"><section class="page-hero compact"><div><span class="eyebrow">{{mode==='待发药'?'DISPENSING QUEUE':'DISPENSING HISTORY'}}</span><h1>{{mode==='待发药'?'待发药队列':'发药记录'}}</h1><p>{{mode==='待发药'?'逐项核对处方药品，确认无误后完成发药':'查询已完成处方，追溯发药时间与药品明细'}}</p></div><div class="hero-metric"><span>{{mode==='待发药'?'等待处理':'累计记录'}}</span><strong>{{total}}</strong><small>张处方</small></div></section><section class="content-card"><div class="toolbar"><div class="search"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索患者、医生或处方号" clearable/><el-date-picker v-model="date" type="date" placeholder="选择日期" value-format="YYYY-MM-DD" clearable/></div><el-button :icon="Refresh" @click="loadData">刷新队列</el-button></div><el-table :data="filtered" v-loading="loading" class="pharmacy-table"><el-table-column label="处方信息" min-width="185"><template #default="{row}"><div class="plain-cell"><strong>RX{{String(row.id).padStart(6,'0')}}</strong><small>{{formatDate(row.createTime)}}</small></div></template></el-table-column><el-table-column label="患者" min-width="150"><template #default="{row}"><div class="plain-cell"><strong>{{row.patientName}}</strong><small>患者ID {{row.patientId}}</small></div></template></el-table-column><el-table-column label="开方医生" min-width="130"><template #default="{row}">{{cleanDoctorName(row.doctorName)}}</template></el-table-column><el-table-column label="药品" min-width="105"><template #default="{row}"><span class="drug-chip">{{parseDrugs(row.drugs).length}} 种 / {{drugTotal(row.drugs)}} 件</span></template></el-table-column><el-table-column label="金额" min-width="100"><template #default="{row}"><strong class="amount">¥{{Number(row.totalAmount).toFixed(2)}}</strong></template></el-table-column><el-table-column label="状态" min-width="100"><template #default="{row}"><el-tag :type="row.status==='待发药'?'warning':'success'" round effect="light">{{row.status}}</el-tag></template></el-table-column><el-table-column v-if="mode==='已发药'" label="发药时间" min-width="160"><template #default="{row}">{{formatDate(row.dispenseTime)}}</template></el-table-column><el-table-column v-if="mode==='待发药'" label="操作" width="120" fixed="right"><template #default="{row}"><el-button type="primary" size="small" @click="openDispense(row)">核对发药</el-button></template></el-table-column></el-table><div class="pagination"><span>共 {{total}} 条记录</span><el-pagination v-model:current-page="page" :page-size="size" :total="total" layout="prev,pager,next" @current-change="loadData"/></div></section><el-drawer v-model="drawer" size="560px" :with-header="false"><div v-if="current" class="rx-detail"><div class="drawer-head"><span class="rx-logo">Rx</span><div><small>PRESCRIPTION DETAIL</small><h2>处方明细</h2><p>RX{{String(current.id).padStart(6,'0')}}</p></div><button @click="drawer=false"><el-icon><Close/></el-icon></button></div><div class="patient-banner"><div><span>患者姓名</span><strong>{{current.patientName}}</strong></div><div><span>开方医生</span><strong>{{cleanDoctorName(current.doctorName)}}</strong></div><div><span>开方时间</span><strong>{{formatDate(current.createTime)}}</strong></div></div><h3>药品清单 <em>{{parseDrugs(current.drugs).length}} 种</em></h3><div class="drug-list"><article v-for="(d,i) in parseDrugs(current.drugs)" :key="drugKey(d,i)"><span class="drug-index">{{i+1}}</span><div><strong>{{drugName(d)}}</strong><small>{{d.specification||'规格未录入'}}</small><p><el-icon><Guide/></el-icon>{{d.dosage||'请遵医嘱使用'}}</p></div><b>× {{d.quantity}} {{d.unit||'件'}}</b></article></div><div class="rx-total"><span>处方总金额</span><strong>¥{{Number(current.totalAmount).toFixed(2)}}</strong></div><div v-if="current.status==='待发药'" class="verify-box"><h3>发药前核对</h3><el-checkbox v-model="verified.patient">患者身份已核对</el-checkbox><el-checkbox v-model="verified.drugs">药品名称与规格已核对</el-checkbox><el-checkbox v-model="verified.quantity">药品数量与用法已核对</el-checkbox><el-checkbox v-model="verified.guidance">已准备向患者进行用药交代</el-checkbox></div><el-button v-if="current.status==='待发药'" type="primary" size="large" class="dispense-btn" :disabled="!allVerified" :loading="dispensing" @click="confirmDispense">确认无误，完成发药</el-button><div v-else class="done-banner"><el-icon><CircleCheckFilled/></el-icon><div><strong>处方已完成发药</strong><span>{{formatDate(current.dispenseTime)}}</span></div></div></div></el-drawer></div></template>
<script setup lang="ts">import{computed,ref,watch}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{Search,Refresh,Close,Guide,CircleCheckFilled}from'@element-plus/icons-vue';import{dispense,getPrescription,getPrescriptions}from'@/api/pharmacy';import type{Drug,Prescription}from'@/types';const props=defineProps<{mode:string}>(),loading=ref(false),dispensing=ref(false),page=ref(1),size=ref(10),total=ref(0),list=ref<Prescription[]>([]),keyword=ref(''),date=ref(''),drawer=ref(false),current=ref<Prescription>(),verified=ref({patient:false,drugs:false,quantity:false,guidance:false});const parseDrugs=(s:string):Drug[]=>{try{return JSON.parse(s||'[]')}catch{return[]}};const cleanDoctorName=(name?:string)=>(name||'--').replace(/医生$/,'').trim();const drugName=(d:any)=>d.medicineName||d.name||d.drugName||d.medicine_name||'药品名称未录入';const drugKey=(d:any,i:number)=>d.medicineId||d.id||`${drugName(d)}-${i}`;const drugTotal=(s:string)=>parseDrugs(s).reduce((n,d:any)=>n+Number(d.quantity||0),0);const formatDate=(s?:string)=>s?new Date(s).toLocaleString('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}):'--';const filtered=computed(()=>list.value.filter(x=>(!keyword.value||x.patientName?.includes(keyword.value)||x.doctorName?.includes(keyword.value)||String(x.id).includes(keyword.value))&&(!date.value||x.createTime?.startsWith(date.value))));const allVerified=computed(()=>Object.values(verified.value).every(Boolean));const loadData=async()=>{loading.value=true;try{const r=await getPrescriptions(props.mode,page.value,size.value);list.value=r.data.data.content;total.value=r.data.data.totalElements}finally{loading.value=false}};const openDetail=async(row:Prescription)=>{current.value=(await getPrescription(row.id)).data.data;verified.value={patient:false,drugs:false,quantity:false,guidance:false};drawer.value=true};const openDispense=openDetail;const confirmDispense=async()=>{await ElMessageBox.confirm('发药完成后不可撤回，确认处方及药品均核对无误？','确认发药',{type:'warning',confirmButtonText:'确认发药'});dispensing.value=true;try{await dispense(current.value!.id);ElMessage.success('发药成功，处方已归档');drawer.value=false;loadData()}finally{dispensing.value=false}};watch(()=>props.mode,()=>{page.value=1;loadData()},{immediate:true})</script>

